#include <stdio.h>
#include <stdlib.h>
#include <math.h>

void wiener_filter(double **G, double **H, double **Sn, double **Sf, int rows, int cols) {
  double **F̂ = (double **)malloc(rows * sizeof(double *));
  for (int i = 0; i < rows; i++) {
    F̂[i] = (double *)malloc(cols * sizeof(double));
  }

  for (int u = 0; u < rows; u++) {
    for (int v = 0; v < cols; v++) {
      if (H[u][v] != 0) {
        F̂[u][v] = (1 / H[u][v]) * (pow(H[u][v], 2) / (pow(H[u][v], 2) + Sn[u][v]/Sf[u][v])) * G[u][v];
      } else {
        F̂[u][v] = 0;
      }
    }
  }

  // Print the restored image
  for (int i = 0; i < rows; i++) {
    for (int j = 0; j < cols; j++) {
      printf("%f ", F̂[i][j]);
    }
    printf("\n");
  }

  // Free memory
  for (int i = 0; i < rows; i++) {
    free(F̂[i]);
  }
  free(F̂);
}

int main() {
  int rows = 256;
  int cols = 256;
  double **G = (double **)malloc(rows * sizeof(double *));
  double **H = (double **)malloc(rows * sizeof(double *));
  double **Sn = (double **)malloc(rows * sizeof(double *));
  double **Sf = (double **)malloc(rows * sizeof(double *));

  // Initialize G, H, Sn, Sf
  for (int i = 0; i < rows; i++) {
    G[i] = (double *)malloc(cols * sizeof(double));
    H[i] = (double *)malloc(cols * sizeof(double));
    Sn[i] = (double *)malloc(cols * sizeof(double));
    Sf[i] = (double *)malloc(cols * sizeof(double));
  }

  // Call the Wiener filter function
  wiener_filter(G, H, Sn, Sf, rows, cols);

  return 0;
}
